import UIKit

class StockTradeViewController: UIViewController {
    
    let stockSymbolTextField = UITextField()
    let quantityTextField = UITextField()
    let buyButton = UIButton()
    let sellButton = UIButton()
    let portfolioTableView = UITableView()
    
    var portfolio: [Stock] = []

    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }

    func setupUI() {
        // Setup text fields and buttons
        stockSymbolTextField.placeholder = "Enter Stock Symbol"
        quantityTextField.placeholder = "Enter Quantity"
        buyButton.setTitle("Buy", for: .normal)
        sellButton.setTitle("Sell", for: .normal)
        
        buyButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
        sellButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
        
        // Layout code for text fields and buttons...
        
        portfolioTableView.dataSource = self
        portfolioTableView.delegate = self
    }

    @objc func executeTrade(sender: UIButton) {
        guard let symbol = stockSymbolTextField.text, let quantity = Int(quantityTextField.text ?? "") else { return }
        let isBuy = sender == buyButton
        trade(symbol: symbol, quantity: quantity, isBuy: isBuy)
    }

    func trade(symbol: String, quantity: Int, isBuy: Bool) {
        let url = URL(string: "https://api.yourtradingplatform.com/trade")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(getAuthToken())", forHTTPHeaderField: "Authorization")

        let tradeRequest = TradeRequest(symbol: symbol, quantity: quantity, isBuy: isBuy)
        request.httpBody = try? JSONEncoder().encode(tradeRequest)

        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard let data = data, error == nil else { return }
            let tradeResponse = try? JSONDecoder().decode(TradeResponse.self, from: data)
            DispatchQueue.main.async {
                if let tradeResponse = tradeResponse {
                    self.updatePortfolio(with: tradeResponse)
                }
            }
        }
        task.resume()
    }

    func updatePortfolio(with tradeResponse: TradeResponse) {
        // Update portfolio logic
        portfolio.append(tradeResponse.stock)
        portfolioTableView.reloadData()
    }
    
    func getAuthToken() -> String {
        // Securely fetch stored auth token
        return "your_auth_token"
    }
}

extension StockTradeViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolio.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "PortfolioCell", for: indexPath)
        let stock = portfolio[indexPath.row]
        cell.textLabel?.text = "\(stock.symbol): \(stock.quantity)"
        return cell
    }
}

struct TradeRequest: Codable {
    let symbol: String
    let quantity: Int
    let isBuy: Bool
}

struct TradeResponse: Codable {
    let stock: Stock
}

struct Stock: Codable {
    let symbol: String
    let quantity: Int
}